import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { installedPluginRegistry } from "../registry.config.mjs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const packageDir = path.resolve(__dirname, "..");
const repoRoot = path.resolve(packageDir, "..", "..");
const srcDir = path.join(packageDir, "src");

const GENERATED_HEADER =
  "// AUTO-GENERATED by plugins/installed/scripts/generate-surface-registries.mjs. Do not edit manually.\n";

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function assertNoDuplicates(label, values) {
  const seen = new Set();
  for (const value of values) {
    if (seen.has(value)) {
      throw new Error(`Duplicate ${label} in installed plugin registry: ${value}`);
    }
    seen.add(value);
  }
}

async function resolveRegistryEntry(entry) {
  const packageDir = path.join(repoRoot, entry.workspaceDir);
  const packageJson = JSON.parse(
    await readFile(path.join(packageDir, "package.json"), "utf8"),
  );
  if (packageJson.name !== entry.packageName) {
    throw new Error(
      `Installed plugin registry package mismatch for ${entry.workspaceDir}: expected ${entry.packageName}, found ${packageJson.name}`,
    );
  }

  const descriptorMatch = entry.descriptorImport.match(/^(@vivd\/[^/]+)\/descriptor$/);
  if (!descriptorMatch) {
    throw new Error(`Unsupported plugin descriptor import: ${entry.descriptorImport}`);
  }
  if (descriptorMatch[1] !== entry.packageName) {
    throw new Error(
      `Descriptor import ${entry.descriptorImport} does not match package ${entry.packageName}`,
    );
  }

  return {
    ...entry,
    descriptorPath: path.join(packageDir, "src", "descriptor.ts"),
  };
}

async function readSurfaceExports(descriptorPath) {
  const source = await readFile(descriptorPath, "utf8");
  const surfaceBlock = source.match(/surfaceExports:\s*\{([\s\S]*?)\}/m);
  if (!surfaceBlock) {
    return {};
  }

  const readSurface = (surface) => {
    const match = surfaceBlock[1].match(
      new RegExp(`${escapeRegExp(surface)}:\\s*"([^"]+)"`),
    );
    return match?.[1];
  };

  return {
    backend: readSurface("backend"),
    frontend: readSurface("frontend"),
    cli: readSurface("cli"),
  };
}

function buildRegistryFile({ imports, body }) {
  return `${GENERATED_HEADER}${imports.join("\n")}\n\n${body.trim()}\n`;
}

function makeImportAlias(index) {
  return `installedPlugin${index}`;
}

function makeDescriptorArray(aliases) {
  return aliases.map((alias) => `  ${alias},`).join("\n");
}

assertNoDuplicates(
  "installed plugin package",
  installedPluginRegistry.map(({ packageName }) => packageName),
);
assertNoDuplicates(
  "installed plugin workspace",
  installedPluginRegistry.map(({ workspaceDir }) => workspaceDir),
);
assertNoDuplicates(
  "installed plugin descriptor import",
  installedPluginRegistry.map(({ descriptorImport }) => descriptorImport),
);

const installedPlugins = await Promise.all(
  installedPluginRegistry.map(async (entry, index) => {
    const resolvedEntry = await resolveRegistryEntry(entry);
    return {
      ...resolvedEntry,
      alias: makeImportAlias(index),
      surfaceExports: await readSurfaceExports(resolvedEntry.descriptorPath),
    };
  }),
);

const descriptorImports = installedPlugins.map(
  ({ alias, descriptorImport }) => `import ${alias} from "${descriptorImport}";`,
);

await writeFile(
  path.join(srcDir, "index.ts"),
  buildRegistryFile({
    imports: [
      'import {',
      '  definePluginBundleEntries,',
      '  definePluginPackageDescriptors,',
      '  extractPluginIds,',
      '} from "@vivd/plugin-sdk";',
      ...descriptorImports,
    ],
    body: `
export const installedPluginDescriptors =
  definePluginBundleEntries([
${makeDescriptorArray(installedPlugins.map(({ alias }) => alias))}
  ] as const);

export const installedPluginManifests = definePluginPackageDescriptors(
  installedPluginDescriptors.map((descriptor) => descriptor.manifest) as readonly (
    typeof installedPluginDescriptors
  )[number]["manifest"][],
);

export const INSTALLED_PLUGIN_IDS = extractPluginIds(installedPluginManifests);
export type InstalledPluginId = (typeof INSTALLED_PLUGIN_IDS)[number];
export type InstalledPluginDescriptor =
  (typeof installedPluginDescriptors)[number];

export function listInstalledPluginAgentHints(
  enabledPluginIds?: readonly string[],
): string[] {
  const enabled = new Set(
    (enabledPluginIds ?? []).map((pluginId) => pluginId.trim()).filter(Boolean),
  );
  if (enabled.size === 0) return [];

  const seen = new Set<string>();
  const hints: string[] = [];

  for (const descriptor of installedPluginDescriptors) {
    if (!enabled.has(descriptor.pluginId)) continue;

    const definition = descriptor.manifest.definition;
    const agentHints =
      "agentHints" in definition && Array.isArray(definition.agentHints)
        ? definition.agentHints
        : [];

    for (const hint of agentHints) {
      const line = \`\${descriptor.manifest.definition.name}: \${hint}\`;
      if (seen.has(line)) continue;
      seen.add(line);
      hints.push(line);
    }
  }

  return hints;
}
`,
  }),
  "utf8",
);

await writeFile(
  path.join(srcDir, "backend.ts"),
  buildRegistryFile({
    imports: [
      'import { definePluginPackageDescriptors } from "@vivd/plugin-sdk";',
      ...installedPlugins.flatMap(({ alias, surfaceExports }) =>
        surfaceExports.backend
          ? [`import ${alias} from "${surfaceExports.backend}";`]
          : [],
      ),
    ],
    body: `
export const installedBackendPluginPackages = definePluginPackageDescriptors([
${makeDescriptorArray(
  installedPlugins
    .filter(({ surfaceExports }) => surfaceExports.backend)
    .map(({ alias }) => alias),
)}
] as const);
`,
  }),
  "utf8",
);

await writeFile(
  path.join(srcDir, "frontend.ts"),
  buildRegistryFile({
    imports: [
      'import {',
      '  buildSharedProjectPluginUiRegistry,',
      '  definePluginPackageDescriptors,',
      '} from "@vivd/plugin-sdk";',
      'import { installedPluginManifests } from "./index";',
      'import type { ComponentType } from "react";',
      'import type {',
      '  PluginPackageDescriptor,',
      '  SharedProjectPluginUiDefinition,',
      '} from "@vivd/plugin-sdk";',
      ...installedPlugins.flatMap(({ alias, surfaceExports }) =>
        surfaceExports.frontend
          ? [`import ${alias} from "${surfaceExports.frontend}";`]
          : [],
      ),
    ],
    body: `
interface InstalledFrontendPluginModule {
  pluginId: string;
  projectUi?: SharedProjectPluginUiDefinition & {
    ProjectPage?: ComponentType<{
      projectSlug: string;
      isEmbedded?: boolean;
    }>;
    OperatorPage?: ComponentType<{
      projectSlug: string;
    }>;
  };
}

type FrontendPluginPackage = PluginPackageDescriptor<
  string,
  InstalledFrontendPluginModule
>;

export const installedFrontendPluginDescriptors =
  definePluginPackageDescriptors([
${makeDescriptorArray(
  installedPlugins
    .filter(({ surfaceExports }) => surfaceExports.frontend)
    .map(({ alias }) => alias),
)}
  ] as const satisfies readonly FrontendPluginPackage[]);

export const installedFrontendSharedProjectPluginUiRegistry =
  buildSharedProjectPluginUiRegistry(installedPluginManifests);

export const installedFrontendPluginModules =
  installedFrontendPluginDescriptors.flatMap((descriptor) =>
    descriptor.frontend ? [descriptor.frontend] : [],
  );
`,
  }),
  "utf8",
);

await writeFile(
  path.join(srcDir, "cli.ts"),
  buildRegistryFile({
    imports: [
      'import { definePluginPackageDescriptors } from "@vivd/plugin-sdk";',
      'import type { PluginPackageDescriptor } from "@vivd/plugin-sdk";',
      ...installedPlugins.flatMap(({ alias, surfaceExports }) =>
        surfaceExports.cli ? [`import ${alias} from "${surfaceExports.cli}";`] : [],
      ),
    ],
    body: `
type CliPluginPackage = PluginPackageDescriptor<string, unknown>;

export const installedCliPluginDescriptors = definePluginPackageDescriptors([
${makeDescriptorArray(
  installedPlugins
    .filter(({ surfaceExports }) => surfaceExports.cli)
    .map(({ alias }) => alias),
)}
] as const satisfies readonly CliPluginPackage[]);
`,
  }),
  "utf8",
);
